constexpr int DATA[] = {5, 2, 8, 1, 9, 3};

int main() {
    constexpr std::span<const int> view(DATA);
    constexpr int total = sum_span(view);
    std::print("sum = {}\n", total);

    constexpr int mx = max_of_sorted({4, 7, 2, 9, 1});
    std::print("max = {}\n", mx);

    constexpr std::size_t sz    = view.size();
    constexpr int         first = view.front();
    std::print("view.size={} view.front={}\n", sz, first);
}

