// Simulates what constexpr std::allocator does internally:
// allocate raw memory -> get void* -> cast to T* -> work with objects
constexpr int sum_via_alloc(int n) {
    std::allocator<int> alloc;
    int* p = alloc.allocate(n);  // internally: allocates as void*, casts to int*

    for (int i = 0; i < n; ++i)
        std::construct_at(p + i, i + 1);

    int result = 0;
    for (int i = 0; i < n; ++i)
        result += p[i];

    for (int i = 0; i < n; ++i)
        std::destroy_at(p + i);
    alloc.deallocate(p, n);
    return result;
}

